<?php
declare(strict_types=1);
require __DIR__.'/../src/bootstrap.php';
use CredentialApi\Config\Env; use CredentialApi\Controllers\CredentialsController; use CredentialApi\Errors\HttpError; use CredentialApi\Errors\ValidationError; use CredentialApi\Http\Headers; use CredentialApi\Idp\BearerToken; use CredentialApi\Idp\TokenValidator; use CredentialApi\Middleware\ApiKey; use CredentialApi\Middleware\ContractHeaders; use CredentialApi\Middleware\CredentialAccess; use CredentialApi\Repositories\UserCredentialRepository; use CredentialApi\Services\CredentialService;
Env::load(dirname(__DIR__));
function respond(int $s,array $p):void{http_response_code($s);header('Content-Type: application/json');echo json_encode($p,JSON_THROW_ON_ERROR|JSON_UNESCAPED_SLASHES);} try{ $path=parse_url($_SERVER['REQUEST_URI']??'/',PHP_URL_PATH)?:'/'; $method=$_SERVER['REQUEST_METHOD']??'GET'; if($path==='/health'){respond(200,['status'=>'ok']);return;} if($method!=='GET'||$path!=='/credentials')throw new HttpError(404,'Resource not found'); ContractHeaders::validate(); ApiKey::validate(); $user=(new TokenValidator())->validate(BearerToken::extract(Headers::get('authorization'))); CredentialAccess::require($user); $controller=new CredentialsController(new CredentialService(new UserCredentialRepository())); respond(200,$controller->getCredentials($user)); } catch(HttpError $e){ if($e->statusCode===204){http_response_code(204);return;} respond($e->statusCode,['message'=>$e->getMessage()]); } catch(ValidationError $e){ $p=['message'=>'University server has an error']; if(Env::env()!=='production')$p['issues']=$e->issues; respond(500,$p); } catch(Throwable){ respond(500,['message'=>'University server has an error']); }
